// // This module implements a synchronous 8-bit register with an active-high clear input and an active-high load signal. On the falling edge of the clock, if the clear signal is high, the output is reset to zero. If the load signal is high, the register captures the input value; otherwise, the output retains its previous value.
module top_module(
	output reg [7:0] BRegister_out,
	input [7:0] BRegister_in,
	input lb_,
	input clk,
	input clr_
	);always @(posedge clk)
		if(~clr_) BRegister_out <= 8'b0;
		else if(~lb_) BRegister_out <= BRegister_in;	

endmodule
